test('addTask crea una tarea con titulo correcto y estado pendiente', () => {
  // Preparar
  const input = { title: 'Comprar comestibles' };

  // Actuar
  const task = addTask(input);

  // Verificar
  expect(task.title).toBe('Comprar comestibles');
  expect(task.status).toBe('pending');
  expect(task.id).toBeDefined();
});
